  rule_default_reply: { bg:'Здравей, {name}! Получих съобщението ти в {time}. Ще се върна към теб скоро.', ru:'Привет, {name}! Получил твоё сообщение в {time}. Скоро вернусь к тебе.', uk:'Привіт, {name}! Отримав твоє повідомлення о {time}. Скоро повернуся до тебе.', en:'Hi {name}! I got your message at {time}. I’ll get back to you soon.', de:'Hallo {name}! Ich habe deine Nachricht um {time} erhalten. Ich melde mich bald.', fr:'Salut {name} ! J’ai reçu ton message à {time}. Je reviens vers toi bientôt.', es:'¡Hola {name}! Recibí tu mensaje a las {time}. Te respondo pronto.', 'es-MX':'¡Hola {name}! Recibí tu mensaje a las {time}. Te respondo pronto.', it:'Ciao {name}! Ho ricevuto il tuo messaggio alle {time}. Ti rispondo presto.', pt:'Olá {name}! Recebi sua mensagem às {time}. Já te respondo.', ar:'مرحبًا {name}! استلمت رسالتك في {time}. سأعود إليك قريبًا.', hi:'नमस्ते {name}! आपका संदेश {time} पर मिला। जल्द ही जवाब दूँगा।', ja:'こんにちは {name} さん！{time} にメッセージを受け取りました。すぐにお返事します。', ky:'Салам {name}! Билдирүүңдү {time}-да алдым. Жакында кайра байланышам.', 'zh-Hant':'你好 {name}！我在 {time} 收到你的訊息，很快回覆你。' },
